        1000000,
        true,
        true,
        false,
        'https://ai.google.dev/gemini-api/docs/models/gemini-3.1-flash-lite-preview',
        false
      ),

      -- -----------------------------------------------------------------------
      -- Mistral models
      -- -----------------------------------------------------------------------
      (
        'Mistral Large 3',
        ARRAY['chat','tools','json_schema']::text[],
        'mistral-large-3',
        'mistral',
        128000,
        true,
        true,
        false,
        'https://docs.mistral.ai/models/mistral-large-3-25-12',
        false
      ),
      (
        'Magistral Medium 1.2',
        ARRAY['chat','reasoning']::text[],
        'magistral-medium-1.2',
        'mistral',
        40000,
        false,
        false,
        false,
        'https://docs.mistral.ai/models/magistral-medium-1-2-25-09',
        false
      ),
      (
        'Magistral Small 1.2',
        ARRAY['chat','reasoning']::text[],
        'magistral-small-1.2',
        'mistral',
        40000,
        false,
        false,
        false,
        'https://docs.mistral.ai/models/magistral-small-1-2-25-09',
        false
      )
  ) AS t(
    name,
    capabilities,
    key,
    provider_key,
    context_window_tokens,
    supports_tools,
    supports_json_schema,
    supports_vision,
    provider_url,
    is_active
  )
),
resolved AS (
  SELECT
    ms.name,
    ms.capabilities,
    ms.key,
    p.id AS provider_id,
    ms.context_window_tokens,
    ms.supports_tools,
    ms.supports_json_schema,
    ms.supports_vision,
    ms.provider_url,
    ms.is_active
  FROM model_seed ms
  JOIN ai.providers p
    ON p.key = ms.provider_key
)

-- Upsert: insert new rows, update existing rows on key conflict
INSERT INTO ai.models (
  name,
  capabilities,
  key,
  provider_id,
  context_window_tokens,
  supports_tools,
  supports_json_schema,
  supports_vision,
  provider_url,
  is_active
)
SELECT
  r.name,
  r.capabilities,
  r.key,
  r.provider_id,
  r.context_window_tokens,
  r.supports_tools,
  r.supports_json_schema,
  r.supports_vision,
  r.provider_url,
  r.is_active
FROM resolved r
ON CONFLICT (key) DO UPDATE SET
  name                   = EXCLUDED.name,
  capabilities           = EXCLUDED.capabilities,
  provider_id            = EXCLUDED.provider_id,
  context_window_tokens  = EXCLUDED.context_window_tokens,
  supports_tools         = EXCLUDED.supports_tools,
  supports_json_schema   = EXCLUDED.supports_json_schema,
  supports_vision        = EXCLUDED.supports_vision,
  provider_url           = EXCLUDED.provider_url,
  is_active              = EXCLUDED.is_active;

