      (v_wf_research_pdf, v_n_r_intent,   v_n_r_research, 'output', 'context'),
      (v_wf_research_pdf, v_n_r_research, v_n_r_refine,   'output', 'draft'),
      (v_wf_research_pdf, v_n_r_refine,   v_n_r_validate, 'output', 'output'),
